using System;
using System.IO;
using System.Threading;
using System.Windows.Forms;

namespace Updater_Server
{
    static class Program
    {
        [STAThread]
        static void Main()
        {
            // 전역 예외 핸들러
            Application.ThreadException += (s, e) => LogCrash(e.Exception);
            AppDomain.CurrentDomain.UnhandledException += (s, e) => LogCrash((Exception)e.ExceptionObject);

            // 중복 실행 방지
            using var mutex = new Mutex(true, "Updater_Server", out bool created);
            if (!created)
            {
                MessageBox.Show("이미 실행 중입니다.", "Updater Server",
                    MessageBoxButtons.OK, MessageBoxIcon.Warning);
                return;
            }

            Application.EnableVisualStyles();
            Application.SetCompatibleTextRenderingDefault(false);
            Application.Run(new FrmMain());
        }

        static void LogCrash(Exception ex)
        {
            try
            {
                var path = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "crash.log");
                var msg = $"[{DateTime.Now:yyyy-MM-dd HH:mm:ss}] {ex.Source}: {ex.Message}\r\n{ex.StackTrace}\r\n\r\n";
                File.AppendAllText(path, msg);
            }
            catch { }
        }
    }
}

