using System;
using System.Drawing;
using System.IO;
using System.Linq;
using System.Threading.Tasks;
using System.Windows.Forms;

namespace Updater_Server
{
    public partial class FrmMain : Form
    {
        private ServerConfig _config;
        private bool _sending = false;

        public FrmMain()
        {
            InitializeComponent();
            _config = ServerConfig.Load();
            LoadStations();
        }

        /// <summary>설정 파일의 스테이션 목록을 그리드에 로드</summary>
        private void LoadStations()
        {
            dgvStations.Rows.Clear();
            foreach (var st in _config.Stations)
            {
                // exe 경로가 있으면 파일명만 표시, 없으면 "(클릭하여 선택)"
                string displayName = string.IsNullOrEmpty(st.ExePath)
                    ? "(클릭하여 선택)"
                    : Path.GetFileName(st.ExePath);

                bool hasExe = !string.IsNullOrEmpty(st.ExePath) && File.Exists(st.ExePath);

                int idx = dgvStations.Rows.Add(hasExe, st.Name, st.IP, st.Port, displayName, "대기");
                dgvStations.Rows[idx].Tag = st;

                // exe 파일이 없거나 경로가 유효하지 않으면 빨간색
                if (!string.IsNullOrEmpty(st.ExePath) && !File.Exists(st.ExePath))
                {
                    dgvStations.Rows[idx].Cells["colExePath"].Style.ForeColor = Color.Red;
                    dgvStations.Rows[idx].Cells["colStatus"].Value = "파일 없음";
                    dgvStations.Rows[idx].Cells["colStatus"].Style.ForeColor = Color.Red;
                }
            }
        }

        /// <summary>그리드 셀 클릭 - exe 컬럼이면 파일 다이얼로그</summary>
        private void dgvStations_CellClick(object sender, DataGridViewCellEventArgs e)
        {
            if (e.RowIndex < 0) return;
            if (e.ColumnIndex != dgvStations.Columns["colExePath"].Index) return;

            var row = dgvStations.Rows[e.RowIndex];
            var station = row.Tag as StationInfo;
            if (station == null) return;

            // 파일 다이얼로그
            using var dlg = new OpenFileDialog
            {
                Title = $"{station.Name} - 실행파일 선택",
                Filter = "실행파일 (*.exe)|*.exe|모든 파일 (*.*)|*.*"
            };

            // 기존 경로가 있으면 해당 폴더로
            if (!string.IsNullOrEmpty(station.ExePath) && Directory.Exists(Path.GetDirectoryName(station.ExePath)))
                dlg.InitialDirectory = Path.GetDirectoryName(station.ExePath)!;

            if (dlg.ShowDialog() != DialogResult.OK) return;

            // 설정 업데이트 + 저장
            station.ExePath = dlg.FileName;
            _config.Save();

            // 그리드 업데이트
            row.Cells["colExePath"].Value = Path.GetFileName(dlg.FileName);
            row.Cells["colExePath"].Style.ForeColor = Color.Black;
            row.Cells["colSelect"].Value = true;
            row.Cells["colStatus"].Value = "대기";
            row.Cells["colStatus"].Style.ForeColor = Color.Black;

            AppendLog($"[{station.Name}] exe 설정: {dlg.FileName}");
        }

        /// <summary>전체 선택/해제 토글</summary>
        private void btnSelectAll_Click(object sender, EventArgs e)
        {
            bool allChecked = dgvStations.Rows.Cast<DataGridViewRow>()
                .All(r => Convert.ToBoolean(r.Cells["colSelect"].Value));

            foreach (DataGridViewRow row in dgvStations.Rows)
                row.Cells["colSelect"].Value = !allChecked;

            btnSelectAll.Text = allChecked ? "전체 선택" : "전체 해제";
        }

        /// <summary>선택된 스테이션에 전송</summary>
        private async void btnSend_Click(object sender, EventArgs e)
        {
            if (_sending)
            {
                MessageBox.Show("전송 중입니다. 완료 후 다시 시도하세요.", "알림",
                    MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }

            // 선택된 스테이션 중 exe 파일이 유효한 것만 필터
            var selectedRows = dgvStations.Rows.Cast<DataGridViewRow>()
                .Where(r => Convert.ToBoolean(r.Cells["colSelect"].Value))
                .ToList();

            if (selectedRows.Count == 0)
            {
                MessageBox.Show("전송 대상 스테이션을 선택하세요.", "알림",
                    MessageBoxButtons.OK, MessageBoxIcon.Warning);
                return;
            }

            // exe 파일 유효성 검사
            var invalidRows = selectedRows.Where(r =>
            {
                var st = r.Tag as StationInfo;
                return st == null || string.IsNullOrEmpty(st.ExePath) || !File.Exists(st.ExePath);
            }).ToList();

            if (invalidRows.Count > 0)
            {
                var names = string.Join(", ", invalidRows.Select(r => r.Cells["colName"].Value));
                MessageBox.Show($"다음 스테이션의 exe 파일이 지정되지 않았거나 존재하지 않습니다:\n{names}",
                    "알림", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                return;
            }

            // 전송 확인
            var stationList = string.Join("\n", selectedRows.Select(r =>
            {
                var st = r.Tag as StationInfo;
                return $"  {st!.Name} → {Path.GetFileName(st.ExePath)}";
            }));
            var result = MessageBox.Show(
                $"다음 스테이션에 전송하시겠습니까?\n\n{stationList}",
                "전송 확인", MessageBoxButtons.YesNo, MessageBoxIcon.Question);

            if (result != DialogResult.Yes) return;

            _sending = true;
            btnSend.Enabled = false;
            btnSend.Text = "전송 중...";

            AppendLog($"=== 전송 시작: {selectedRows.Count}개 스테이션 ===");

            // 선택된 스테이션에 병렬 전송
            var tasks = selectedRows.Select(row => SendToStation(row)).ToArray();
            await Task.WhenAll(tasks);

            // 결과 요약
            int success = selectedRows.Count(r => r.Cells["colStatus"].Value?.ToString() == "완료");
            int fail = selectedRows.Count - success;
            AppendLog($"=== 전송 완료: 성공 {success}, 실패 {fail} ===");

            _sending = false;
            btnSend.Enabled = true;
            btnSend.Text = "전송";
        }

        /// <summary>단일 스테이션에 파일 전송</summary>
        private async Task SendToStation(DataGridViewRow row)
        {
            var station = row.Tag as StationInfo;
            if (station == null) return;

            SetRowStatus(row, "전송 중...", Color.Orange);
            AppendLog($"[{station.Name}] {station.IP}:{station.Port} → {Path.GetFileName(station.ExePath)}");

            var result = await FileSender.SendFileAsync(station.IP, station.Port, station.ExePath,
                (sent, total) =>
                {
                    int pct = (int)(sent * 100 / total);
                    SetRowStatus(row, $"전송 중... {pct}%", Color.Orange);
                });

            if (result.Success)
            {
                SetRowStatus(row, "완료", Color.Green);
                AppendLog($"[{station.Name}] 성공: {result.Message}");
            }
            else
            {
                SetRowStatus(row, $"실패: {result.Message}", Color.Red);
                AppendLog($"[{station.Name}] 실패: {result.Message}");
            }
        }

        /// <summary>그리드 행 상태 업데이트 (UI 스레드 안전)</summary>
        private void SetRowStatus(DataGridViewRow row, string status, Color color)
        {
            if (dgvStations.InvokeRequired)
            {
                dgvStations.Invoke(() => SetRowStatus(row, status, color));
                return;
            }
            row.Cells["colStatus"].Value = status;
            row.Cells["colStatus"].Style.ForeColor = color;
        }

        /// <summary>로그 추가 (UI 스레드 안전)</summary>
        private void AppendLog(string msg)
        {
            if (txtLog.InvokeRequired)
            {
                txtLog.Invoke(() => AppendLog(msg));
                return;
            }
            txtLog.AppendText($"[{DateTime.Now:HH:mm:ss}] {msg}\r\n");
        }
    }
}

