using System;
using System.IO;
using System.Net.Sockets;
using System.Text;
using System.Threading.Tasks;

namespace Updater_Server
{
    public class SendResult
    {
        public bool Success { get; set; }
        public string Message { get; set; } = "";
    }

    public static class FileSender
    {
        // 프로토콜 매직 바이트
        private static readonly byte[] MAGIC_REQ = Encoding.ASCII.GetBytes("NXUP");
        private static readonly byte[] MAGIC_RES = Encoding.ASCII.GetBytes("NXRS");

        /// <summary>파일을 에이전트로 전송</summary>
        public static async Task<SendResult> SendFileAsync(string ip, int port, string filePath,
            Action<long, long>? onProgress = null)
        {
            try
            {
                using var client = new TcpClient();
                client.SendTimeout = 30000;
                client.ReceiveTimeout = 60000;

                // 연결 (3초 타임아웃)
                var connectTask = client.ConnectAsync(ip, port);
                if (await Task.WhenAny(connectTask, Task.Delay(3000)) != connectTask)
                    return new SendResult { Success = false, Message = "연결 타임아웃" };

                if (connectTask.IsFaulted)
                    return new SendResult { Success = false, Message = connectTask.Exception?.InnerException?.Message ?? "연결 실패" };

                var stream = client.GetStream();
                var fileInfo = new FileInfo(filePath);
                string fileName = fileInfo.Name;
                long fileSize = fileInfo.Length;

                // 1. 매직 바이트
                await stream.WriteAsync(MAGIC_REQ);

                // 2. 파일명
                var fnBytes = Encoding.UTF8.GetBytes(fileName);
                await stream.WriteAsync(BitConverter.GetBytes(fnBytes.Length));
                await stream.WriteAsync(fnBytes);

                // 3. 파일 크기
                await stream.WriteAsync(BitConverter.GetBytes(fileSize));

                // 4. 파일 데이터
                using (var fs = File.OpenRead(filePath))
                {
                    var buffer = new byte[65536];
                    long sent = 0;
                    int read;
                    while ((read = await fs.ReadAsync(buffer, 0, buffer.Length)) > 0)
                    {
                        await stream.WriteAsync(buffer, 0, read);
                        sent += read;
                        onProgress?.Invoke(sent, fileSize);
                    }
                }
                await stream.FlushAsync();

                // 5. 응답 수신
                var resMagic = await ReadExact(stream, 4);
                if (!resMagic.AsSpan().SequenceEqual(MAGIC_RES))
                    return new SendResult { Success = false, Message = "잘못된 응답" };

                int status = stream.ReadByte();
                var msgLenBuf = await ReadExact(stream, 4);
                int msgLen = BitConverter.ToInt32(msgLenBuf, 0);
                var msgBuf = await ReadExact(stream, msgLen);
                string message = Encoding.UTF8.GetString(msgBuf);

                return new SendResult
                {
                    Success = status == 0x00,
                    Message = message
                };
            }
            catch (Exception ex)
            {
                return new SendResult { Success = false, Message = ex.Message };
            }
        }

        private static async Task<byte[]> ReadExact(NetworkStream stream, int count)
        {
            var buffer = new byte[count];
            int offset = 0;
            while (offset < count)
            {
                int read = await stream.ReadAsync(buffer, offset, count - offset);
                if (read == 0) throw new IOException("연결 끊김");
                offset += read;
            }
            return buffer;
        }
    }
}

