        /// <summary>선택된 exe 파일 전체 경로 (저장됨)</summary>
        public string ExePath { get; set; } = "";
    }

    public class ServerConfig
    {
        public List<StationInfo> Stations { get; set; } = new();

        private static string ConfigPath =>
            Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "server_config.json");

        public static ServerConfig Load()
        {
            if (!File.Exists(ConfigPath))
            {
                var config = CreateDefault();
                config.Save();
                return config;
            }
            var json = File.ReadAllText(ConfigPath);
            return JsonSerializer.Deserialize<ServerConfig>(json) ?? CreateDefault();
        }

        public void Save()
        {
            var options = new JsonSerializerOptions { WriteIndented = true };
            var json = JsonSerializer.Serialize(this, options);
            File.WriteAllText(ConfigPath, json);
